<script>
// Hàm hỗ trợ (Không cần thay đổi)
function SafeGetValue(obj, path, defaultValue = "N/A") {
    let keys = Array.isArray(path) ? path : path.split('.');
    let current = obj;
    for (let i = 0; i < keys.length; i++) {
        if (current === undefined || current === null) return defaultValue;
        const key = keys[i];
        if (Array.isArray(current)) {
            const index = parseInt(key, 10);
            if (isNaN(index) || index < 0 || index >= current.length) return defaultValue;
            current = current[index];
        } else if (typeof current === 'object' && current.hasOwnProperty(key)) {
            current = current[key];
        } else {
            return defaultValue;
        }
    }
    return (current === undefined || current === null) ? defaultValue : current;
}


const rarityLookup = {
    '神话': { badge: 'UR', css: 'UR' }, 'UR': { badge: 'UR', css: 'UR' },
    '传说': { badge: 'SSR', css: 'SSR' }, 'SSR': { badge: 'SSR', css: 'SSR' },
    '超稀有': { badge: 'SR', css: 'SR' }, 'SR': { badge: 'SR', css: 'SR' },
    '稀有': { badge: 'R', css: 'R' }, 'R': { badge: 'R', css: 'R' },
    '普通': { badge: 'N', css: 'N' }, 'N': { badge: 'N', css: 'N' }
};
function renderDisplayPool(containerId, dataArray, titleIfEmpty) {
    const container = document.getElementById(containerId);
    if (!container) return;
    container.innerHTML = '';
    if (!dataArray || !Array.isArray(dataArray) || dataArray.length === 0) {
        container.innerHTML = `<div class="pool-item rarity-N"><div class="item-content"><p>${titleIfEmpty}</p></div></div>`;
        return;
    }

    let listHTML = '';
    dataArray.forEach(item => {
        if (typeof item === 'object' && item.name) {
             const rarityKey = String(item.rarity || 'N').trim().split(' ')[0];
             const rarityInfo = rarityLookup[rarityKey] || { badge: '?', css: 'N' };
             listHTML += `
                <div class="pool-item rarity-${rarityInfo.css}">
                    <div class="item-content">
                        <strong>${item.name}</strong>
                        <p>${item.description || ''}</p>
                    </div>
                    <div class="rarity-badge">${rarityInfo.badge}</div>
                </div>
            `;
        }
    });
    container.innerHTML = listHTML;
}

function renderChoicePool(containerId, dataArray, poolName, titleIfEmpty) {
    const container = document.getElementById(containerId);
    if (!container) return;
    container.innerHTML = '';

    if (!dataArray || !Array.isArray(dataArray) || dataArray.length === 0) {
        container.innerHTML = `<div class="pool-item rarity-N"><div class="item-content"><p>${titleIfEmpty}</p></div></div>`;
        return;
    }

    let listHTML = '';
    dataArray.forEach(item => {
        if (typeof item === 'object' && item.name) {
            const rarityKey = String(item.rarity || 'N').trim().split(' ')[0];
            const rarityInfo = rarityLookup[rarityKey] || { badge: '?', css: 'N' };
            // 修正：确保 value 中的 JSON 字符串是有效的，特别是处理单引号
            const itemJson = JSON.stringify(item).replace(/'/g, "\\'");

            listHTML += `
                <label class="pool-item-label">
                    <input type="radio" name="${poolName}-choice" value='${itemJson}'>
                    <div class="pool-item rarity-${rarityInfo.css}">
                        <div class="item-content">
                            <strong>${item.name}</strong>
                            <p>${item.description || ''}</p>
                        </div>
                        <div class="rarity-badge">${rarityInfo.badge}</div>
                    </div>
                </label>
            `;
        }
    });
    container.innerHTML = listHTML;
}

function updateStatDisplay(elementId, value) {
    const element = document.getElementById(elementId);
    if (element) {
        const finalValue = Array.isArray(value) ? value[0] : value;
        element.innerText = String(finalValue); // 确保是字符串
    }
}

async function initDisplay() {
    try {
        const messages = getChatMessages('0-{{lastMessageId}}');
        if (!messages || messages.length === 0) {
             console.log("Không tìm thấy tin nhắn hoặc cuộc trò chuyện trống.");
             return;
        }

        let characterData = null;
        for (let i = messages.length - 1; i >= 0; i--) {
            if (messages[i].data && messages[i].data.stat_data) {
                characterData = messages[i].data.stat_data;
                break;
            }
        }

        if (!characterData) {
            console.log("Không tìm thấy stat_data trong bất kỳ tin nhắn nào.");
            return;
        }

        const characterKey = "主神空间";
        if (characterData.hasOwnProperty(characterKey)) {
            // --- Cập nhật dữ liệu cốt lõi ---
            updateStatDisplay('godspace-level', SafeGetValue(characterData, `${characterKey}.核心数据.等级`, 'N/A'));
            const bonusValueRaw = SafeGetValue(characterData, `${characterKey}.当前世界配置.稀有度概率加成`, [0]);
            const bonusPercentage = (parseFloat(Array.isArray(bonusValueRaw) ? bonusValueRaw[0] : bonusValueRaw) * 100).toFixed(2);
            updateStatDisplay('godspace-rarity-bonus', `${bonusPercentage}%`);
            // --- Cập nhật thế giới và bể năng lực ---
            updateStatDisplay('godspace-current-world', SafeGetValue(characterData, `${characterKey}.世界穿梭.当前世界`, '[Chưa chọn]'));
            const permanentAbilitiesData = SafeGetValue(characterData, `${characterKey}.永久能力池`, [[], '']);
            // Trích xuất mảng và hiển thị
            renderDisplayPool('permanent-abilities-list', permanentAbilitiesData[0], 'Bể năng lực vĩnh viễn trống');
            const identityPoolData = SafeGetValue(characterData, `${characterKey}.当前世界配置.身份抽取池`, [[], '']);
            // 【Sửa lỗi】Sử dụng trực tiếp identityPoolData[0], nó đã là một mảng
            renderChoicePool('identity-pool-list', identityPoolData[0], 'identity', 'Bể thân phận trống');
            const abilityPoolData = SafeGetValue(characterData, `${characterKey}.当前世界配置.能力抽取池`, [[], '']);
            // 【Sửa lỗi】Sử dụng trực tiếp abilityPoolData[0], nó đã là một mảng
            renderChoicePool('ability-pool-list', abilityPoolData[0], 'ability', 'Bể năng lực trống');
        } else {
             // Xử lý trường hợp thiếu dữ liệu
             updateStatDisplay('godspace-level', 'Thiếu dữ liệu');
             updateStatDisplay('godspace-rarity-bonus', 'Thiếu dữ liệu');
             updateStatDisplay('godspace-current-world', 'Thiếu dữ liệu');
             renderDisplayPool('permanent-abilities-list', [], 'Thiếu dữ liệu');
             renderChoicePool('identity-pool-list', [], 'identity', 'Thiếu dữ liệu');
             renderChoicePool('ability-pool-list', [], 'ability', 'Thiếu dữ liệu');
        }
    } catch (error) {
        document.getElementById('status-card').innerHTML = `<p style='color:red; padding:20px;'>Lỗi khi tải thanh trạng thái: ${error.message}. Vui lòng đảm bảo bạn đang sử dụng trang này trong môi trường SillyTavern.</p>`;
    }
}

