async function handleFormSubmit(event) {
    event.preventDefault();
    const selectedIdentityRadio = document.querySelector('input[name="identity-choice"]:checked');
    const selectedAbilityRadio = document.querySelector('input[name="ability-choice"]:checked');
    const selectedAge = document.querySelector('input[name="age-appearance"]:checked')?.value || 'Chưa chọn';
    const penisLength = document.getElementById('penis-length').value;
    const customDetails = document.getElementById('custom-details').value;
    // Lấy tên thế giới hiện tại từ khu vực hiển thị
    const currentWorldName = document.getElementById('godspace-current-world').innerText;

    let identityText = 'Chưa chọn';
    if (selectedIdentityRadio) {
        const identityData = JSON.parse(selectedIdentityRadio.value);
        identityText = `${identityData.name} (Độ hiếm: ${identityData.rarity})`;
    }

    let abilityText = 'Chưa chọn';
    if (selectedAbilityRadio) {
        const abilityData = JSON.parse(selectedAbilityRadio.value);
        abilityText = `${abilityData.name} (Độ hiếm: ${abilityData.rarity})`;
    }

    let summary = `【Xác Nhận Thông Tin Tạo Nhân Vật】\n`;
    // 【Logic mới】Kiểm tra xem thế giới hiện tại có giá trị không, nếu có, thêm vào dòng đầu tiên của bản tóm tắt
    if (currentWorldName && currentWorldName.trim() !== '' && currentWorldName !== '[Chưa chọn]') {
        summary += `Thế giới tôi chọn là: ${currentWorldName}\n`;
    }

    // Thêm thông tin khác
    summary += `Thân phận đã chọn: ${identityText}\n`;
    summary += `Năng lực tạm thời đã chọn: ${abilityText}\n`;
    if (customDetails.trim()) {
        summary += `Thiết lập chi tiết tùy chỉnh:\n${customDetails}`;
    } else {
        summary += `Độ tuổi ngoại hình: ${selectedAge}\n`;
