box-shadow: 0 10px 40px rgba(0, 0, 0, 0.7);
display: flex; flex-direction: column;
background: var(--container-gradient);
flex-grow: 1;
}
.card-header {
background-color: transparent;
padding: 0;
height: 110px;
display: flex;
justify-content: center;
align-items: center;
border-bottom: 2px solid var(--card-border-color);
flex-shrink: 0;
overflow: hidden;
position: relative;
}
.card-body { flex-grow: 1;
}
.content-view {
display: none; flex-direction: column; gap: 12px;
padding: 15px; opacity: 0;
transition: opacity 0.5s ease-in-out;
}
.content-view.active { display: flex; opacity: 1; }
.section { background-color: var(--section-bg-color); border-radius: 8px; border: 1px solid rgba(255, 255, 255, 0.1);
}
.section-header { padding: 12px 18px; cursor: pointer; display: flex; justify-content: space-between; align-items: center; font-weight: bold; transition: background-color 0.3s;
}
.section-header:hover { background-color: rgba(255, 255, 255, 0.1); }
.section-header .arrow { transition: transform 0.3s ease-in-out; display: inline-block;
}
.section-content {
overflow: hidden;
transition: max-height 0.5s ease-in-out, padding 0.5s ease-in-out;
display: flex; flex-direction: column; gap: 12px;
padding: 18px;
max-height: 5000px;
}
.section-content:not(.expanded) {
max-height: 0;
padding-top: 0;
padding-bottom: 0;
}
.property { background-color: var(--property-bg-color);
padding: 10px 14px; border-radius: 6px; display: flex; flex-direction: column; gap: 6px; }
.property-row { display: flex; justify-content: space-between; align-items: center;
flex-wrap: wrap; }
.property-name { font-weight: 500; color: var(--secondary-text-color); }
.property-value, .description-text { font-weight: bold; text-align: right; line-height: 1.5;
}
.description-text { text-align: left; width: 100%; font-weight: normal; color: var(--primary-text-color); white-space: pre-wrap; margin-top: 5px; }
.progress-bar-container { width: 100%; height: 8px;
background-color: rgba(0, 0, 0, 0.4); border-radius: 4px; overflow: hidden; margin-top: 4px; }
.progress-bar-value { height: 100%; border-radius: 4px;
transition: width 0.5s ease-in-out; }
.list-container ul { list-style-type: none; padding-left: 0; margin: 5px 0 0 0; display: flex; flex-direction: column;
gap: 8px; }
.list-container li { background-color: var(--header-bg-color); padding: 3px 10px; border-radius: 12px; font-size: 1.1em; border: 1px solid var(--card-border-color);
}
.script-list { display: flex; flex-direction: column; gap: 10px; }
.script-item { border: 1px solid var(--card-border-color); border-radius: 6px; padding: 10px; background-color: var(--property-bg-color);
}
.script-title { font-weight: bold; font-size: 1.3em; color: var(--highlight-color); margin-bottom: 5px; }
.script-detail { font-size: 1.1em; margin-top: 5px;
}
.script-detail strong { color: var(--secondary-text-color); }

.ability-item { border: 1px solid var(--card-border-color); border-radius: 6px; padding: 10px; background-color: var(--property-bg-color); display: flex;
flex-direction: column; gap: 5px; }
.ability-header { display: flex; justify-content: space-between; align-items: center; }
.ability-name { font-weight: bold; font-size: 1.3em; color: var(--highlight-color);
}
.ability-rarity { font-weight: bold; padding: 2px 8px; border-radius: 10px; font-size: 1.0em; text-shadow: 1px 1px 2px rgba(0,0,0,0.5); }
.rarity-N { background-color: #9E9E9E;
color: white; }
.rarity-R { background-color: #2196F3; color: white; }
.rarity-SR { background-color: #9C27B0; color: white; }
.rarity-SSR { background: linear-gradient(45deg, #FFD700, #F0E68C);
color: #333; }
.rarity-UR { background: linear-gradient(45deg, #ff2d2d, #ff8a8a); color: white; }
.ability-description { font-size: 1.1em; color: var(--secondary-text-color); white-space: pre-wrap; line-height: 1.5;
}

.story-container { width: 100%; padding: 20px 30px; box-shadow: 0 20px 60px rgba(255, 20, 147, 0.8); position: relative; background-color: rgba(0,0,0,0.2);
border-radius: 8px; }
.story-container::before, .story-container::after { content: ''; position: absolute; pointer-events: none; }
.story-container::before { top: -50%; left: -50%; width: 200%;
height: 200%; background: radial-gradient(circle, rgba(255, 20, 147, 0.2) 0%, transparent 70%); animation: skinGlow 8s infinite ease-in-out; z-index: 1;
}
.story-container::after { top: 0; left: 0; width: 100%; height: 100%; box-shadow: inset 0 0 40px rgba(255, 20, 147, 0.9);
z-index: 2; border-radius: 8px; }
.story-content { text-align: justify; font-size: 1.5rem; position: relative; z-index: 3; line-height: 2.2; white-space: pre-wrap;
}
.heart { position: fixed; width: 20px; height: 20px; transform-origin: center center; animation: heartFade 1s ease-out forwards; pointer-events: none; z-index: 9999;
}
.heart > div { background: rgba(255, 20, 147, 0.8); }

.header-decoration { width: 98%; height: 100%; max-width: 900px;
animation: header-breathe 10s infinite ease-in-out; }
.header-decoration path { fill: none; stroke-linecap: round; stroke-linejoin: round; stroke-dasharray: 2500; stroke-dashoffset: 2500;
animation: draw-in 10s cubic-bezier(0.65, 0, 0.35, 1) infinite; }
.tattoo-wing { stroke: var(--highlight-color); stroke-width: 3; }
.tattoo-detail { stroke: var(--card-border-color); stroke-width: 1.5;
opacity: 0.8; }
.tattoo-core { stroke: var(--highlight-color); stroke-width: 2.5; }
.tattoo-jewel { stroke: #ffabdf; stroke-width: 2; fill: var(--lust-color); fill-opacity: 0;
animation: jewel-pulse 2.5s ease-in-out infinite, draw-in 10s cubic-bezier(0.65, 0, 0.35, 1) infinite; filter: drop-shadow(0 0 8px #ffabdf);
}
/* NEW: Style for the floating particles */
.tattoo-particle {
fill: rgba(255, 171, 223, 0.7);
stroke: none;
filter: drop-shadow(0 0 4px #ffabdf);
animation: particle-float 8s ease-in-out infinite;
opacity: 0;
}

@keyframes heartFade { 0% { transform: scale(1) rotate(45deg);
opacity: 0.9; } 100% { transform: scale(2) translateY(-40px) rotate(45deg); opacity: 0; } }
@keyframes skinGlow { 0%, 100% { transform: rotate(0deg);
opacity: 0.35; } 50% { transform: rotate(180deg); opacity: 0.5; } }
@keyframes header-breathe { 0%, 100% { transform: translateY(0) scale(1);
} 50% { transform: translateY(-5px) scale(1.02); } }
@keyframes draw-in { 50%, 100% { stroke-dashoffset: 0;
} }
@keyframes jewel-pulse { 0%, 100% { transform: scale(1); fill-opacity: 0.3; filter: drop-shadow(0 0 8px var(--highlight-color));
} 50% { transform: scale(1.2); fill-opacity: 0.8; filter: drop-shadow(0 0 20px #ffabdf);
} }
/* NEW: Keyframes for the particle animation */
@keyframes particle-float {
0%, 100% {
opacity: 0;
transform: translateY(10px) rotate(0deg) scale(0.7);
}
50% {
opacity: 1;
transform: translateY(-20px) rotate(180deg) scale(1);
}
}

@media (max-width: 768px) {
body { align-items: center;
}
.main-layout { flex-direction: column; padding: 10px; gap: 10px; }
.sidebar { flex-direction: row;
width: 100% !important; position: static; }
.sidebar.collapsed { width: 100% !important;
